import React, { useState, useEffect } from 'react';
import { auth, firestore } from '../firebase';
import { collection, addDoc, onSnapshot, query, orderBy, serverTimestamp, doc, updateDoc, increment } from 'firebase/firestore';
import './Discussion.css';

const Discussion = ({ pageId, title }) => {
  const [comments, setComments] = useState([]);
  const [newComment, setNewComment] = useState('');
  const [replies, setReplies] = useState({});
  const [newReplies, setNewReplies] = useState({});
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const q = query(
      collection(firestore, 'discussions', pageId, 'comments'),
      orderBy('timestamp', 'desc')
    );

    const unsubscribe = onSnapshot(q, (snapshot) => {
      const commentsData = snapshot.docs.map(doc => ({
        id: doc.id,
        ...doc.data()
      }));
      setComments(commentsData);
      setLoading(false);
    });

    return () => unsubscribe();
  }, [pageId]);

  const handleSubmitComment = async (e) => {
    e.preventDefault();
    if (!newComment.trim() || !auth.currentUser) return;

    try {
      await addDoc(collection(firestore, 'discussions', pageId, 'comments'), {
        content: newComment,
        authorId: auth.currentUser.uid,
        authorName: auth.currentUser.displayName || 'Anonymous',
        authorPhoto: auth.currentUser.photoURL || '/default-avatar.png',
        timestamp: serverTimestamp(),
        likes: 0,
        dislikes: 0
      });
      setNewComment('');
    } catch (error) {
      console.error('Error adding comment:', error);
    }
  };

  const handleLike = async (commentId) => {
    if (!auth.currentUser) return;
    try {
      const commentRef = doc(firestore, 'discussions', pageId, 'comments', commentId);
      await updateDoc(commentRef, {
        likes: increment(1)
      });
    } catch (error) {
      console.error('Error updating likes:', error);
    }
  };

  const handleDislike = async (commentId) => {
    if (!auth.currentUser) return;
    try {
      const commentRef = doc(firestore, 'discussions', pageId, 'comments', commentId);
      await updateDoc(commentRef, {
        dislikes: increment(1)
      });
    } catch (error) {
      console.error('Error updating dislikes:', error);
    }
  };

  const handleSubmitReply = async (commentId) => {
    if (!newReplies[commentId]?.trim() || !auth.currentUser) return;

    try {
      const replyRef = collection(firestore, 'discussions', pageId, 'comments', commentId, 'replies');
      await addDoc(replyRef, {
        content: newReplies[commentId],
        authorId: auth.currentUser.uid,
        authorName: auth.currentUser.displayName || 'Anonymous',
        authorPhoto: auth.currentUser.photoURL || '/default-avatar.png',
        timestamp: serverTimestamp()
      });
      setNewReplies(prev => ({ ...prev, [commentId]: '' }));
    } catch (error) {
      console.error('Error adding reply:', error);
    }
  };

  if (loading) {
    return (
      <div className="discussion-container">
        <div className="loading">Loading comments...</div>
      </div>
    );
  }

  if (!auth.currentUser) {
    return (
      <div className="discussion-container">
        <h2>{title} Discussion</h2>
        <div className="login-prompt">
          <p>Please log in to participate in the discussion.</p>
        </div>
      </div>
    );
  }

  return (
    <div className="discussion-container">
      <h2>{title} Discussion</h2>

      <form className="comment-form" onSubmit={handleSubmitComment}>
        <textarea
          value={newComment}
          onChange={(e) => setNewComment(e.target.value)}
          placeholder="Share your thoughts..."
          rows="4"
        />
        <button type="submit" className="submit-comment-button">Comment</button>
      </form>

      <div className="comments">
        {comments.map(comment => (
          <div key={comment.id} className="comment">
            <div className="comment-header">
              <img
                src={comment.authorPhoto || '/default-avatar.png'}
                alt={comment.authorName}
                className="author-avatar"
              />
              <div className="comment-info">
                <strong>{comment.authorName}</strong>
                <span className="timestamp">
                  {comment.timestamp?.toDate().toLocaleDateString()}
                </span>
              </div>
            </div>

            <div className="comment-content">
              <p>{comment.content}</p>
            </div>

            <div className="comment-actions">
              <button onClick={() => handleLike(comment.id)}>
                👍 {comment.likes || 0}
              </button>
              <button onClick={() => handleDislike(comment.id)}>
                👎 {comment.dislikes || 0}
              </button>
            </div>

            <div className="replies">
              {replies[comment.id]?.map(reply => (
                <div key={reply.id} className="reply">
                  <div className="reply-header">
                    <img
                      src={reply.authorPhoto || '/default-avatar.png'}
                      alt={reply.authorName}
                      className="author-avatar small"
                    />
                    <div className="reply-info">
                      <strong>{reply.authorName}</strong>
                      <span className="timestamp">
                        {reply.timestamp?.toDate().toLocaleDateString()}
                      </span>
                    </div>
                  </div>
                  <p>{reply.content}</p>
                </div>
              ))}

              <div className="reply-form">
                <textarea
                  value={newReplies[comment.id] || ''}
                  onChange={(e) =>
                    setNewReplies(prev => ({
                      ...prev,
                      [comment.id]: e.target.value
                    }))
                  }
                  placeholder="Write a reply..."
                  rows="2"
                />
                <button
                  className="submit-reply-button"
                  onClick={() => handleSubmitReply(comment.id)}
                >
                  Reply
                </button>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default Discussion;
